def get_symbol_detail(symbol: str) -> dict:
    symbol = str(symbol or "").upper().strip()

    detail = {
        "symbol": symbol,
        "company": {
            "name": symbol,
            "blurb": "Engine-generated symbol intelligence.",
        },
        "board": {
            "symbol": symbol,
            "company_name": symbol,
            "latest_score": 0,
            "latest_confidence": "LOW",
            "latest_timestamp": "",
            "opinion": "No active opinion available.",
        },
        "primary_intelligence": {},
        "signals": [],
        "news_items": [],
        "engine_intelligence": {},
        "engine_verdict": {},
        "soulanna": {},
        "v2_intelligence": {
            "regime_alignment": "",
            "signal_strength": 0.0,
            "conviction_adjustment": 0.0,
            "vehicle_bias": "",
            "thesis": "",
            "notes": [],
            "risk_flags": [],
        },
    }

    try:
        from engine.engine_selection import build_execution_universe
    except Exception:
        build_execution_universe = None

    try:
        signals = load_json("data/signals.json", [])
    except Exception:
        signals = []

    try:
        system_state = load_json(
            "data/system_state.json",
            {"regime": "Neutral", "volatility": "Normal"},
        )
    except Exception:
        system_state = {"regime": "Neutral", "volatility": "Normal"}

    selected = []
    if build_execution_universe:
        try:
            universe = build_execution_universe(signals, system_state)
            selected = universe.get("selected", []) if isinstance(universe, dict) else []
        except Exception:
            selected = []

    match = None
    for row in selected:
        if str(row.get("symbol", "")).upper().strip() == symbol:
            match = row
            break

    if not isinstance(match, dict):
        return detail

    v2 = match.get("v2", {}) if isinstance(match.get("v2"), dict) else {}

    v2_regime_alignment = str(
        match.get("v2_regime_alignment", v2.get("regime_alignment", "")) or ""
    ).strip()
    v2_signal_strength = float(
        match.get("v2_signal_strength", v2.get("signal_strength", 0.0)) or 0.0
    )
    v2_conviction_adjustment = float(
        match.get("v2_conviction_adjustment", v2.get("conviction_adjustment", 0.0)) or 0.0
    )
    v2_vehicle_bias = str(
        match.get("v2_vehicle_bias", v2.get("vehicle_bias", "")) or ""
    ).strip().upper()
    v2_thesis = str(
        match.get("v2_thesis", v2.get("thesis", "")) or ""
    ).strip()
    v2_notes = match.get("v2_notes", v2.get("notes", []))
    v2_risk_flags = match.get("v2_risk_flags", v2.get("risk_flags", []))

    if not isinstance(v2_notes, list):
        v2_notes = []
    if not isinstance(v2_risk_flags, list):
        v2_risk_flags = []

    company_name = match.get("company_name", symbol)

    detail["board"] = {
        "symbol": symbol,
        "company_name": company_name,
        "latest_score": match.get("fused_score", match.get("score", 0)),
        "latest_confidence": match.get("confidence", "LOW"),
        "latest_timestamp": match.get("timestamp", ""),
        "opinion": match.get(
            "opinion",
            match.get(
                "decision_reason",
                "Engine-selected candidate.",
            ),
        ),
    }

    detail["company"] = {
        "name": company_name,
        "blurb": match.get(
            "company_blurb",
            "Engine-generated symbol intelligence.",
        ),
    }

    detail["primary_intelligence"] = {
        "direction": match.get("strategy", "CALL"),
        "setup_type": match.get("setup_type", "continuation"),
        "setup_family": match.get("setup_family", ""),
        "entry_quality": match.get("entry_quality", ""),
        "score": match.get("fused_score", match.get("score")),
        "confidence": match.get("confidence"),
        "vehicle_selected": match.get("vehicle_selected", "RESEARCH_ONLY"),
        "vehicle_reason": match.get("vehicle_reason", ""),
    }

    detail["v2_intelligence"] = {
        "regime_alignment": v2_regime_alignment,
        "signal_strength": v2_signal_strength,
        "conviction_adjustment": v2_conviction_adjustment,
        "vehicle_bias": v2_vehicle_bias,
        "thesis": v2_thesis,
        "notes": v2_notes,
        "risk_flags": v2_risk_flags,
    }

    detail["engine_intelligence"] = {
        "readiness_score": match.get("readiness_score"),
        "promotion_score": match.get("promotion_score"),
        "rebuild_pressure": match.get("rebuild_pressure"),
        "execution_quality": match.get("execution_quality"),
        "eligible": match.get("eligible"),
        "final_verdict": match.get("final_verdict"),
        "decision_reason": match.get("decision_reason", match.get("final_reason", "")),
        "final_decision": match.get("final_decision", {}),
        "canonical_decision": match.get("canonical_decision", {}),
        "learning_notes": match.get("learning_notes", []),
        "promotion_notes": match.get("promotion_notes", []),
        "rebuild_notes": match.get("rebuild_notes", []),
        "setup_family": match.get("setup_family"),
        "entry_quality": match.get("entry_quality"),
        "vehicle_selected": match.get("vehicle_selected", "RESEARCH_ONLY"),
        "vehicle_reason": match.get("vehicle_reason", ""),
        "capital_required": match.get("capital_required"),
        "minimum_trade_cost": match.get("minimum_trade_cost"),
        "gates": {
            "readiness": match.get("readiness_gate_passed"),
            "promotion": match.get("promotion_gate_passed"),
            "rebuild": match.get("rebuild_gate_passed"),
        },
    }

    verdict_notes = [
        f"Final Verdict: {match.get('final_verdict')}",
        f"Decision Reason: {match.get('decision_reason', match.get('final_reason', ''))}",
        f"Readiness: {match.get('readiness_score')}",
        f"Promotion: {match.get('promotion_score')}",
        f"Rebuild Pressure: {match.get('rebuild_pressure')}",
        f"Eligible: {match.get('eligible')}",
        f"Vehicle: {match.get('vehicle_selected', 'RESEARCH_ONLY')}",
    ]

    if v2_regime_alignment:
        verdict_notes.append(f"V2 Regime Alignment: {v2_regime_alignment}")
    if v2_signal_strength:
        verdict_notes.append(f"V2 Signal Strength: {v2_signal_strength}")
    if v2_conviction_adjustment:
        verdict_notes.append(f"V2 Conviction Adjustment: {v2_conviction_adjustment}")
    if v2_vehicle_bias:
        verdict_notes.append(f"V2 Vehicle Bias: {v2_vehicle_bias}")
    if v2_thesis:
        verdict_notes.append(f"V2 Thesis: {v2_thesis}")
    if v2_risk_flags:
        verdict_notes.append(f"V2 Risk Flags: {', '.join(str(x) for x in v2_risk_flags)}")

    detail["engine_verdict"] = {
        "headline": "Engine-evaluated opportunity.",
        "summary": (
            "This symbol is being actively scored across readiness, promotion, "
            "rebuild pressure, V2 context, and final decision logic."
        ),
        "notes": verdict_notes,
    }

    try:
        detail["soulanna"] = soulanna_explain_signal(
            {
                "symbol": symbol,
                "score": match.get("fused_score", match.get("score", 0)),
                "confidence": match.get("confidence", "LOW"),
                "setup_family": match.get("setup_family"),
                "entry_quality": match.get("entry_quality"),
                "readiness_score": match.get("readiness_score"),
                "promotion_score": match.get("promotion_score"),
                "rebuild_pressure": match.get("rebuild_pressure"),
                "eligible": match.get("eligible"),
                "final_verdict": match.get("final_verdict"),
                "decision_reason": match.get("decision_reason", match.get("final_reason", "")),
                "canonical_decision": match.get("canonical_decision", {}),
                "learning_notes": match.get("learning_notes", []),
                "vehicle_selected": match.get("vehicle_selected", "RESEARCH_ONLY"),
                "vehicle_reason": match.get("vehicle_reason", ""),
                "v2": {
                    "regime_alignment": v2_regime_alignment,
                    "signal_strength": v2_signal_strength,
                    "conviction_adjustment": v2_conviction_adjustment,
                    "vehicle_bias": v2_vehicle_bias,
                    "thesis": v2_thesis,
                    "notes": v2_notes,
                    "risk_flags": v2_risk_flags,
                },
            }
        ) or {}
    except Exception:
        detail["soulanna"] = {}

    return detail


def build_symbol_news_impact(
    symbol: str,
    company: dict | None = None,
    news_items: list | None = None,
    board: dict | None = None,
    final_brain: dict | None = None,
    final_symbol_context: dict | None = None,
) -> dict:
    symbol = str(symbol or "").upper().strip()
    company = safe_dict(company)
    board = safe_dict(board)
    final_brain = safe_dict(final_brain)
    final_symbol_context = safe_dict(final_symbol_context)
    news_items = safe_list(news_items)

    company_name = company.get("name", symbol)
    action = str(final_symbol_context.get("hero_action", "wait") or "wait").strip().lower()
    confidence = str(final_symbol_context.get("hero_confidence", "low") or "low").strip().lower()
    coaching_tone = str(final_symbol_context.get("coaching_tone", "neutral") or "neutral").strip().lower()

    if not news_items:
        return {
            "headline": f"News field for {symbol}",
            "summary": f"Soulanna does not have fresh news context loaded for {company_name} yet.",
            "symbol_impact": "Unknown",
            "market_scope": "Unknown",
            "stance": action.title(),
            "confidence": confidence.title(),
            "takeaway": "Wait for fresh headlines before letting news change the thesis.",
            "symbol_drivers": [],
            "market_drivers": [],
            "watch_items": [],
            "thesis_shift": "",
        }

    titles = []
    blob_parts = []

    for item in news_items[:6]:
        if not isinstance(item, dict):
            continue
        title = str(item.get("title", "") or "").strip()
        if title:
            titles.append(title)
            blob_parts.append(title.lower())

    blob = " | ".join(blob_parts)

    bullish_terms = ["beats", "beat", "upgrade", "upgraded", "surge", "rally", "approval", "growth", "record", "raises guidance", "buyback"]
    bearish_terms = ["misses", "miss", "downgrade", "downgraded", "warning", "lawsuit", "probe", "cuts guidance", "decline", "delay", "layoffs"]
    macro_terms = ["fed", "rates", "inflation", "cpi", "jobs report", "treasury", "bond yields", "recession", "oil", "tariff", "regulation"]
    sector_terms = ["semiconductor", "software", "cloud", "ai", "retail", "banking", "energy", "biotech", "consumer", "ev"]

    bullish_hits = sum(1 for term in bullish_terms if term in blob)
    bearish_hits = sum(1 for term in bearish_terms if term in blob)
    macro_hits = sum(1 for term in macro_terms if term in blob)
    sector_hits = sum(1 for term in sector_terms if term in blob)

    if bullish_hits > bearish_hits + 1:
        symbol_impact = "Bullish"
    elif bearish_hits > bullish_hits + 1:
        symbol_impact = "Bearish"
    elif bullish_hits > 0 or bearish_hits > 0:
        symbol_impact = "Mixed"
    else:
        symbol_impact = "Neutral"

    if macro_hits >= 2:
        market_scope = "Macro spillover"
    elif sector_hits >= 1:
        market_scope = "Sector influence"
    else:
        market_scope = "Company-specific"

    if symbol_impact == "Bullish":
        headline = f"News tone is leaning constructive for {symbol}"
        summary = f"Soulanna reads the recent headline field around {company_name} as supportive, but still wants price and structure confirmation."
    elif symbol_impact == "Bearish":
        headline = f"News tone is pressuring {symbol}"
        summary = f"Soulanna reads the recent headline field around {company_name} as adding friction, so the market may demand cleaner confirmation."
    elif symbol_impact == "Mixed":
        headline = f"News tone is mixed for {symbol}"
        summary = f"Soulanna sees conflicting headline pressure around {company_name}, so the story is not clean enough to trust on headlines alone."
    else:
        headline = f"News is not clearly shifting the {symbol} thesis"
        summary = f"Soulanna does not see strong headline evidence that the recent news field is materially changing the setup for {company_name} yet."

    if action in {"take", "buy", "enter"} and symbol_impact == "Bearish":
        thesis_shift = "News is working against the current action bias, so conviction should stay tighter."
    elif action in {"wait", "watch"} and symbol_impact == "Bullish":
        thesis_shift = "News may be improving the setup, but Soulanna still wants structure to confirm the story."
    elif action in {"exit", "block", "protect"} and symbol_impact == "Bearish":
        thesis_shift = "The news field supports a more defensive posture."
    else:
        thesis_shift = "The news field should be treated as context, not a standalone trigger."

    symbol_drivers = []
    market_drivers = []
    watch_items = []

    if symbol_impact == "Bullish":
        symbol_drivers.extend([
            "Headline tone is helping sentiment around the symbol.",
            "The news field may support stronger narrative follow-through if price confirms.",
        ])
    elif symbol_impact == "Bearish":
        symbol_drivers.extend([
            "Headline tone is introducing friction into the symbol story.",
            "The market may punish weak structure faster while this pressure is active.",
        ])
    elif symbol_impact == "Mixed":
        symbol_drivers.extend([
            "Headline flow is conflicted, so conviction should not come from news alone.",
            "The setup needs cleaner confirmation from behavior, structure, and follow-through.",
        ])
    else:
        symbol_drivers.append("Recent headlines are not clearly changing the symbol thesis yet.")

    if market_scope == "Macro spillover":
        market_drivers.extend([
            "This headline set appears broad enough to affect more than one ticker.",
            "Sector and market posture may matter as much as the company-specific story.",
        ])
    elif market_scope == "Sector influence":
        market_drivers.extend([
            "The news field may spill into peers and sector sentiment.",
            "Relative strength versus the sector should matter here.",
        ])
    else:
        market_drivers.append("The impact looks more local to this company than market-wide.")

    if confidence == "high":
        watch_items.append("Watch whether price action confirms the current high-conviction posture.")
    else:
        watch_items.append("Wait for price confirmation before letting headlines change conviction.")

    if coaching_tone in {"protective", "cautious"}:
        watch_items.append("Stay alert for overreaction risk and avoid emotional chasing.")
    else:
        watch_items.append("Use the news field as a clue, not a command.")

    if titles:
        watch_items.append(f"Most recent driver: {titles[0]}")

    return {
        "headline": headline,
        "summary": summary,
        "symbol_impact": symbol_impact,
        "market_scope": market_scope,
        "stance": action.title(),
        "confidence": confidence.title(),
        "takeaway": thesis_shift,
        "symbol_drivers": symbol_drivers[:4],
        "market_drivers": market_drivers[:4],
        "watch_items": watch_items[:4],
        "thesis_shift": thesis_shift,
    }


def load_json(path: str, default: Any) -> Any:
    try:
        file_path = Path(path)
        if not file_path.exists():
            return default
        with open(file_path, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return default


def save_json(path: str, payload: Any) -> None:
    file_path = Path(path)
    file_path.parent.mkdir(parents=True, exist_ok=True)
    with open(file_path, "w", encoding="utf-8") as f:
        json.dump(payload, f, indent=2)


def load_canonical_closed_trade_ledger():
    candidates = [
        ("data/trade_journal_export.csv", "csv"),
        ("data/trade_replay_source.json", "json"),
        ("data/trade_details.json", "json"),
    ]

    rows = []

    for path, kind in candidates:
        try:
            if kind == "csv":
                if not os.path.exists(path):
                    continue

                import csv
                with open(path, "r", encoding="utf-8") as f:
                    reader = csv.DictReader(f)
                    for row in reader:
                        rows.append(dict(row))

                if rows:
                    break

            elif kind == "json":
                data = load_json(path, [])
                if isinstance(data, list) and data:
                    rows = data
                    break

        except Exception as e:
            print(f"[CANONICAL_LEDGER_LOAD:{path}] {e}")

    normalized = []

    for row in rows:
        try:
            if not isinstance(row, dict):
                continue

            symbol = str(row.get("symbol", "") or row.get("ticker", "") or "").upper().strip()
            if not symbol:
                continue

            pnl_raw = row.get("pnl", row.get("realized_pnl", row.get("profit_loss", 0)))
            try:
                pnl = float(pnl_raw or 0)
            except Exception:
                pnl = 0.0

            direction = str(row.get("direction", row.get("strategy", row.get("side", ""))) or "").upper().strip()
            outcome = str(row.get("outcome", "") or "").strip().lower()

            if not outcome:
                if pnl > 0:
                    outcome = "win"
                elif pnl < 0:
                    outcome = "loss"
                else:
                    outcome = "flat"

            opened_at = row.get("opened_at") or row.get("entry_time") or row.get("timestamp") or ""
            closed_at = row.get("closed_at") or row.get("exit_time") or row.get("timestamp") or ""

            normalized.append({
                "symbol": symbol,
                "direction": direction or "UNKNOWN",
                "pnl": pnl,
                "outcome": outcome,
                "opened_at": opened_at,
                "closed_at": closed_at,
                "raw": row,
            })

        except Exception as e:
            print(f"[CANONICAL_LEDGER_NORMALIZE:{row}] {e}")

    return normalized


def enrich_trade_record(base: Dict[str, Any]) -> Dict[str, Any]:
    if not isinstance(base, dict):
        return {}

    enriched = dict(base)
    raw = base.get("raw", {}) if isinstance(base.get("raw"), dict) else {}

    symbol = enriched.get("symbol") or raw.get("symbol")
    direction = enriched.get("direction") or raw.get("direction") or raw.get("strategy")
    pnl = float(enriched.get("pnl", 0) or 0)

    score_raw = raw.get("score", 0)
    confidence_raw = raw.get("confidence", "")
    reason_raw = str(raw.get("reason", "") or "").strip().upper()
    exit_explanation = str(raw.get("exit_explanation", "") or "").strip()

    try:
        score = float(score_raw or 0)
    except Exception:
        score = 0.0

    confidence = str(confidence_raw or "").strip().upper()

    enriched["symbol"] = symbol
    enriched["direction"] = direction
    enriched["pnl"] = pnl
    enriched["score"] = score
    enriched["confidence"] = confidence

    if reason_raw == "TAKE_PROFIT" and score >= 180 and confidence == "HIGH":
        setup_family = "high_score_momentum"
    elif reason_raw == "TAKE_PROFIT" and score >= 120:
        setup_family = "strong_structured"
    elif reason_raw in {"CUT_WEAKNESS", "MANUAL", "STOP_LOSS"} and score >= 180:
        setup_family = "failed_high_score_momentum"
    elif reason_raw in {"CUT_WEAKNESS", "MANUAL", "STOP_LOSS"} and score >= 120:
        setup_family = "failed_structured"
    elif score >= 180 and confidence == "HIGH":
        setup_family = "high_score_momentum"
    elif score >= 120:
        setup_family = "structured"
    else:
        setup_family = "speculative"

    enriched["setup_family"] = setup_family

    if reason_raw == "TAKE_PROFIT":
        entry_quality = "high_conviction_win" if score >= 180 and confidence == "HIGH" else "acceptable_win"
    elif reason_raw == "CUT_WEAKNESS":
        entry_quality = "cut_on_weakness"
    elif reason_raw == "MANUAL":
        entry_quality = "manual_exit_loss"
    elif reason_raw == "STOP_LOSS":
        entry_quality = "stopped_out" if score < 180 else "high_conviction_loss"
    elif pnl > 0 and score >= 180 and confidence == "HIGH":
        entry_quality = "high_conviction_win"
    elif pnl > 0:
        entry_quality = "acceptable_win"
    elif pnl <= 0 and score >= 180 and confidence == "HIGH":
        entry_quality = "high_conviction_loss"
    elif pnl <= 0 and score >= 120:
        entry_quality = "failed_clean"
    elif pnl <= 0 and score >= 70:
        entry_quality = "weak_followthrough"
    else:
        entry_quality = "weak"

    enriched["entry_quality"] = entry_quality

    enriched["exit_reason"] = reason_raw
    enriched["exit_explanation"] = exit_explanation

    failure_reason = ""
    success_reason = ""

    if enriched.get("outcome") == "loss":
        if reason_raw == "STOP_LOSS":
            failure_reason = "stopped_out"
        elif reason_raw == "CUT_WEAKNESS":
            failure_reason = "cut_on_weakness"
        elif reason_raw == "MANUAL":
            failure_reason = "manual_exit_loss"
        elif score < 100:
            failure_reason = "weak_entry_structure"
        else:
            failure_reason = "loss_after_entry"
    elif enriched.get("outcome") == "win":
        if reason_raw == "TAKE_PROFIT":
            success_reason = "target_hit"
        elif score >= 180 and confidence == "HIGH":
            success_reason = "high_conviction_win"
        else:
            success_reason = "profitable_exit"

    enriched["failure_reason"] = failure_reason
    enriched["success_reason"] = success_reason

    enriched["market_regime"] = "unknown"
    enriched["volatility_state"] = "unknown"
    enriched["breadth"] = "unknown"
    enriched["engine_agreement"] = None
    enriched["thesis"] = []
    enriched["notes"] = ""

    return enriched


# ============================================================
# SECTION 73ZH — CALIBRATED SETUP FAMILY CLASSIFIER
# ============================================================

def classify_setup_family(trade: Dict[str, Any]) -> str:
    trade = trade or {}

    raw = trade.get("raw", {}) if isinstance(trade.get("raw", {}), dict) else {}

    candidates = [
        trade.get("setup_family"),
        trade.get("setup_type"),
        trade.get("pattern"),
        trade.get("thesis"),
        raw.get("setup_family"),
        raw.get("setup_type"),
        raw.get("pattern"),
        raw.get("thesis"),
        raw.get("notes"),
    ]

    text = " ".join(str(x or "") for x in candidates).strip().lower()

    if not text:
        return "structured"

    if "continuation" in text:
        return "continuation"
    if "breakout" in text:
        return "breakout"
    if "pullback" in text:
        return "pullback"
    if "reversal" in text:
        return "reversal"
    if "mean reversion" in text or "mean_reversion" in text:
        return "mean_reversion"
    if "trend" in text:
        return "trend"
    if "momentum" in text:
        return "momentum"
    if "bounce" in text:
        return "bounce"
    if "support" in text or "resistance" in text:
        return "levels"
    if "range" in text:
        return "range"
    if "scalp" in text:
        return "scalp"

    score = float(trade.get("score", raw.get("score", 0)) or 0)

    if score >= 85:
        return "momentum"
    if score >= 65:
        return "structured"
    return "unclear"


# ============================================================
# ENTRY QUALITY CLASSIFIER
# ============================================================

# ============================================================
# SECTION 73ZI — CALIBRATED ENTRY QUALITY CLASSIFIER
# ============================================================

def classify_entry_quality(trade: Dict[str, Any]) -> str:
    trade = trade or {}

    raw = trade.get("raw", {}) if isinstance(trade.get("raw", {}), dict) else {}

    explicit = str(
        trade.get("entry_quality")
        or raw.get("entry_quality")
        or ""
    ).strip().lower()

    if explicit in {"clean", "great", "ideal", "excellent"}:
        return "clean"
    if explicit in {"acceptable", "fine", "okay", "ok", "decent"}:
        return "acceptable"
    if explicit in {"late", "poor", "bad"}:
        return "late"
    if explicit in {"chased", "chase"}:
        return "chased"

    score = float(trade.get("score", raw.get("score", 0)) or 0)
    pnl = float(trade.get("pnl", 0) or 0)
    confidence = str(trade.get("confidence", raw.get("confidence", "")) or "").strip().upper()

    notes_blob = " ".join(
        str(x or "") for x in [
            trade.get("notes"),
            raw.get("notes"),
            raw.get("thesis"),
        ]
    ).lower()

    if "late" in notes_blob:
        return "late"
    if "chase" in notes_blob or "chased" in notes_blob:
        return "chased"
    if "clean" in notes_blob:
        return "clean"

    if score >= 85 and confidence in {"HIGH", "STRONG"}:
        return "clean"

    if score >= 70:
        return "acceptable"

    if score >= 50:
        return "late"

    if pnl > 0:
        return "acceptable"

    return "late"


def build_canonical_reporting_snapshot():
    # PACK109: Tower object-level permission check.
    _tower_object_response = _tower_object_permission_response_109(
        object_type='export',
        object_id='build_canonical_reporting_snapshot',
        action='export',
        metadata={"source": "pack109_object_route_guard", "route_function": 'build_canonical_reporting_snapshot'},
    )
    if _tower_object_response is not None:
        return _tower_object_response

    raw_trades = load_canonical_closed_trade_ledger()

    closed_trades = []
    for t in raw_trades:
        enriched = enrich_trade_record(t)
        closed_trades.append(enriched)

    total_trades = len(closed_trades)
    wins = sum(1 for x in closed_trades if x.get("outcome") == "win")
    losses = sum(1 for x in closed_trades if x.get("outcome") == "loss")
    flats = sum(1 for x in closed_trades if x.get("outcome") == "flat")

    total_pnl = round(sum(float(x.get("pnl", 0) or 0) for x in closed_trades), 2)
    winrate = round((wins / total_trades), 2) if total_trades else 0.0

    strategy_counts = {}
    strategy_performance = {}

    for row in closed_trades:
        direction = str(row.get("direction", "UNKNOWN") or "UNKNOWN").upper()
        strategy_counts[direction] = strategy_counts.get(direction, 0) + 1

        if direction not in strategy_performance:
            strategy_performance[direction] = {
                "trades": 0,
                "wins": 0,
                "pnl": 0.0,
                "winrate": 0.0,
            }

        strategy_performance[direction]["trades"] += 1
        if row.get("outcome") == "win":
            strategy_performance[direction]["wins"] += 1
        strategy_performance[direction]["pnl"] += float(row.get("pnl", 0) or 0)

    for direction, stats in strategy_performance.items():
        trades = stats["trades"]
        wins_for_direction = stats["wins"]
        stats["pnl"] = round(stats["pnl"], 2)
        stats["winrate"] = round((wins_for_direction / trades), 2) if trades else 0.0

    positions = get_positions_with_intelligence()
    open_positions = [p for p in positions if str(p.get("status", "")).lower() != "closed"]
    closed_position_count = total_trades

    unrealized_total = 0.0
    unrealized_positions = []

    for p in open_positions:
        pnl = float((p.get("pnl") or p.get("unrealized_pnl") or 0) or 0)
        unrealized_total += pnl
        unrealized_positions.append({
            "symbol": p.get("symbol"),
            "unrealized_pnl": pnl,
        })

    unrealized_total = round(unrealized_total, 2)

    realized_pnl = total_pnl
    estimated_account_value = round(1000 + realized_pnl + unrealized_total, 2)
    buying_power = round(max(0, estimated_account_value), 2)

    equity_curve = []
    running_equity = 1000.0
    peak = 1000.0
    max_drawdown = 0.0

    for row in closed_trades:
        running_equity += float(row.get("pnl", 0) or 0)
        peak = max(peak, running_equity)
        drawdown = round(peak - running_equity, 2)
        max_drawdown = max(max_drawdown, drawdown)

        equity_curve.append({
            "equity": round(running_equity, 2),
            "drawdown": drawdown,
            "symbol": row.get("symbol"),
            "closed_at": row.get("closed_at", ""),
        })

    latest_symbol = closed_trades[-1]["symbol"] if closed_trades else None

    enriched_ledger = []
    for row in closed_trades:
        if not isinstance(row, dict):
            continue

        enriched_row = enrich_trade_record(row)
        enriched_ledger.append(enriched_row)

    return {
        "ledger": enriched_ledger,
        "performance": {
            "trades": total_trades,
            "wins": wins,
            "losses": losses,
            "flats": flats,
            "winrate": winrate,
            "total_pnl": total_pnl,
            "max_drawdown": round(max_drawdown, 2),
            "entries_today": 0,
            "closes_today": 0,
            "round_trips_today": 0,
            "realized_pnl_today": 0.0,
        },
        "analytics": {
            "trades": total_trades,
            "winrate": winrate,
            "strategies": strategy_counts,
            "last_trade": latest_symbol,
            "portfolio": {
                "open_positions": len(open_positions),
                "closed_positions": closed_position_count,
                "realized_pnl": realized_pnl,
            },
        },
        "portfolio_summary": {
            "open_positions": len(open_positions),
            "closed_positions": closed_position_count,
            "realized_pnl": realized_pnl,
        },
        "unrealized": {
            "total_unrealized": unrealized_total,
            "positions": unrealized_positions,
        },
        "strategy_performance": strategy_performance,
        "drawdown_history": equity_curve[-50:],
        "final_account_snapshot": {
            "cash": buying_power,
            "buying_power": buying_power,
            "equity": estimated_account_value,
            "open_positions": len(open_positions),
            "realized_pnl": realized_pnl,
            "unrealized_pnl": unrealized_total,
            "estimated_account_value": estimated_account_value,
        },
    }


def write_canonical_reporting_snapshot():
    # PACK109: Tower object-level permission check.
    _tower_object_response = _tower_object_permission_response_109(
        object_type='export',
        object_id='write_canonical_reporting_snapshot',
        action='export',
        metadata={"source": "pack109_object_route_guard", "route_function": 'write_canonical_reporting_snapshot'},
    )
    if _tower_object_response is not None:
        return _tower_object_response

    snapshot = build_canonical_reporting_snapshot()

    try:
        save_json("data/canonical_reporting_snapshot.json", snapshot)
    except Exception as e:
        print(f"[WRITE_CANONICAL_REPORTING_SNAPSHOT] {e}")

    return snapshot


# ============================================================
# SECTION 73N — CANONICAL SNAPSHOT ACCESSOR
# ============================================================

def get_canonical_snapshot():
    """
    Build a canonical snapshot from durable data files so downstream engine layers
    (learning, playbook memory, canonical decision support) always have a stable source.

    This function intentionally avoids relying on transient in-memory globals like
    app_state, because notebook / reload workflows can make those inconsistent.
    """
    try:
        ledger = []
        sources = {}

        # --- load durable sources ---
        try:
            closed_positions = load_json("data/closed_positions.json", [])
        except Exception as e:
            print(f"[SNAPSHOT_LOAD:closed_positions] {e}")
            closed_positions = []

        try:
            trade_log = load_json("data/trade_log.json", [])
        except Exception as e:
            print(f"[SNAPSHOT_LOAD:trade_log] {e}")
            trade_log = []

        try:
            trade_details = load_json("data/trade_details.json", [])
        except Exception as e:
            print(f"[SNAPSHOT_LOAD:trade_details] {e}")
            trade_details = []

        try:
            canonical_ledger = load_json("data/canonical_ledger.json", [])
        except Exception as e:
            print(f"[SNAPSHOT_LOAD:canonical_ledger] {e}")
            canonical_ledger = []

        try:
            open_positions = load_json("data/open_positions.json", [])
        except Exception as e:
            print(f"[SNAPSHOT_LOAD:open_positions] {e}")
            open_positions = []

        try:
            candidate_log = load_json("data/candidate_log.json", [])
        except Exception as e:
            print(f"[SNAPSHOT_LOAD:candidate_log] {e}")
            candidate_log = []

        if not isinstance(closed_positions, list):
            closed_positions = []
        if not isinstance(trade_log, list):
            trade_log = []
        if not isinstance(trade_details, list):
            trade_details = []
        if not isinstance(canonical_ledger, list):
            canonical_ledger = []
        if not isinstance(open_positions, list):
            open_positions = []
        if not isinstance(candidate_log, list):
            candidate_log = []

        sources["closed_positions"] = closed_positions
        sources["trade_log"] = trade_log
        sources["trade_details"] = trade_details
        sources["canonical_ledger"] = canonical_ledger
        sources["open_positions"] = open_positions
        sources["candidate_log"] = candidate_log

        # --- merge into a canonical ledger ---
        merged = []
        seen = set()

        def _safe_str(x, default=""):
            try:
                return str(x)
            except Exception:
                return default

        def _safe_float(x, default=0.0):
            try:
                return float(x)
            except Exception:
                return default

        def _normalize_outcome(row):
            outcome = _safe_str(row.get("outcome", "")).strip().lower()
            if outcome in {"win", "loss", "flat"}:
                return outcome

            pnl = _safe_float(
                row.get("pnl", row.get("realized_pnl", row.get("profit", 0.0))),
                0.0,
            )
            if pnl > 0:
                return "win"
            if pnl < 0:
                return "loss"
            return "flat"

        def _normalize_setup_family(row):
            setup_family = _safe_str(row.get("setup_family", "")).strip().lower()
            if setup_family:
                return setup_family

            setup_type = _safe_str(
                row.get("setup_type", row.get("signal_type", row.get("strategy", "")))
            ).strip().lower()

            mapping = {
                "continuation": "continuation",
                "breakout": "breakout",
                "pullback": "pullback",
                "momentum": "high_score_momentum",
                "high_score_momentum": "high_score_momentum",
                "structured": "structured",
                "strong_structured": "strong_structured",
                "speculative": "speculative",
            }

            if setup_type in mapping:
                return mapping[setup_type]

            if "breakout" in setup_type:
                return "breakout"
            if "pullback" in setup_type:
                return "pullback"
            if "continuation" in setup_type:
                return "continuation"
            if "momentum" in setup_type:
                return "high_score_momentum"

            return "unknown"

        def _infer_entry_quality(row):
            entry_quality = _safe_str(row.get("entry_quality", "")).strip().lower()
            if entry_quality:
                return entry_quality

            learning_notes = row.get("learning_notes", [])
            if not isinstance(learning_notes, list):
                learning_notes = []

            joined_notes = " ".join([_safe_str(x).lower() for x in learning_notes])

            if "cut_on_weakness" in joined_notes:
                return "cut_on_weakness"

            confidence = _safe_str(
                row.get("confidence", row.get("latest_confidence", "LOW"))
            ).strip().upper()
            score = _safe_float(row.get("score", row.get("latest_score", 0.0)), 0.0)

            if confidence == "HIGH" and score >= 160:
                return "high_conviction"
            if confidence in {"HIGH", "MEDIUM"} and score >= 100:
                return "acceptable"
            return "weak"

        def _identity(row):
            trade_id = _safe_str(row.get("trade_id", row.get("id", ""))).strip()
            if trade_id:
                return f"trade:{trade_id}"

            symbol = _safe_str(row.get("symbol", "")).upper().strip()
            timestamp = _safe_str(
                row.get("timestamp", row.get("opened_at", row.get("closed_at", row.get("date", ""))))
            ).strip()
            outcome = _normalize_outcome(row)
            return f"{symbol}|{timestamp}|{outcome}"

        def _build_memory_row(row):
            row = dict(row or {})

            return {
                "trade_id": _safe_str(row.get("trade_id", row.get("id", ""))).strip(),
                "symbol": _safe_str(row.get("symbol", "")).upper().strip(),
                "timestamp": _safe_str(
                    row.get("timestamp", row.get("opened_at", row.get("closed_at", row.get("date", ""))))
                ).strip(),
                "pnl": round(
                    _safe_float(row.get("pnl", row.get("realized_pnl", row.get("profit", 0.0))), 0.0),
                    2,
                ),
                "score": round(
                    _safe_float(row.get("score", row.get("latest_score", 0.0)), 0.0),
                    2,
                ),
                "confidence": _safe_str(
                    row.get("confidence", row.get("latest_confidence", "LOW"))
                ).upper().strip() or "LOW",
                "setup_family": _normalize_setup_family(row),
                "entry_quality": _infer_entry_quality(row),
                "outcome": _normalize_outcome(row),
                "exit_reason": _safe_str(row.get("exit_reason", row.get("close_reason", ""))).strip(),
                "success_reason": _safe_str(row.get("success_reason", "")).strip(),
                "failure_reason": _safe_str(row.get("failure_reason", "")).strip(),
            }

        # Canonical ledger first, then closed positions, then trade log, then trade details
        for source_name in ["canonical_ledger", "closed_positions", "trade_log", "trade_details"]:
            for row in sources.get(source_name, []):
                if not isinstance(row, dict):
                    continue

                normalized = _build_memory_row(row)
                ident = _identity(normalized)

                if ident in seen:
                    continue
                seen.add(ident)

                if not normalized.get("symbol") and not normalized.get("trade_id"):
                    continue

                merged.append(normalized)

        wins = sum(1 for row in merged if row.get("outcome") == "win")
        losses = sum(1 for row in merged if row.get("outcome") == "loss")
        flat = sum(1 for row in merged if row.get("outcome") == "flat")

        snapshot = {
            "ledger": merged,
            "closed_positions": closed_positions,
            "trade_log": trade_log,
            "trade_details": trade_details,
            "canonical_ledger": canonical_ledger,
            "open_positions": open_positions,
            "candidate_log": candidate_log,
            "memory_fuel_summary": {
                "ledger_count": len(merged),
                "wins": wins,
                "losses": losses,
                "flat": flat,
            },
        }

        print("[SNAPSHOT] keys:", list(snapshot.keys()))
        print("[SNAPSHOT] ledger count:", len(snapshot.get("ledger", [])))
        print("[SNAPSHOT] wins/losses/flat:", wins, losses, flat)

        return snapshot

    except Exception as e:
        print(f"[SNAPSHOT_ERROR] {e}")
        return {
            "ledger": [],
            "memory_fuel_summary": {
                "ledger_count": 0,
                "wins": 0,
                "losses": 0,
                "flat": 0,
            },
        }


def performance_summary():
    snapshot = load_json("data/canonical_reporting_snapshot.json", {})
    if not isinstance(snapshot, dict) or not snapshot:
        snapshot = write_canonical_reporting_snapshot()
