    import importlib
    module = importlib.import_module(module_name)
    for function_name in function_candidates:
        fn = getattr(module, function_name, None)
        if callable(fn):
            return fn()
    raise RuntimeError(
        "Vault route repair could not find callable in "
        + module_name
        + ": "
        + ", ".join(function_candidates)
    )

